SELECT S.GENERO FROM CARGO C JOIN SERVIDOR S ON S.PK_SIAPE = C.FK_SIAPE WHERE LOWER(C.SIGLA_CAMPUS) = LOWER('ana') AND (LOWER(C.FUNCAO) LIKE LOWER('%diret%') OR LOWER(C.FUNCAO) LIKE LOWER('%direc%')) AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%engenharia civil%') AND C.DATA_ENTRADA <= DATE('now') AND COALESCE(C.DATA_SAIDA, DATE('now')) >= DATE('now', '-5 years') GROUP BY S.GENERO ORDER BY COUNT(DISTINCT S.PK_SIAPE) DESC LIMIT 1